using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD ERRORS ===");
build.VisitAllChildren<Error>(e =>
{
    Console.WriteLine($"[ERROR] Project: {GetProject(e)} | Code: {e.Code} | File: {e.File}({e.LineNumber},{e.ColumnNumber})");
    Console.WriteLine($"  Message: {e.Message}");
    Console.WriteLine();
});

Console.WriteLine("=== BUILD WARNINGS ===");
build.VisitAllChildren<Warning>(w =>
{
    Console.WriteLine($"[WARN] Project: {GetProject(w)} | Code: {w.Code} | File: {w.File}({w.LineNumber},{w.ColumnNumber})");
    Console.WriteLine($"  Message: {w.Message}");
    Console.WriteLine();
});

Console.WriteLine("=== PROJECT RESULTS ===");
build.VisitAllChildren<Project>(p =>
{
    Console.WriteLine($"Project: {p.Name} | Succeeded: {p.Succeeded}");
});

static string GetProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        current = current.Parent;
    }
    return "(unknown)";
}

