{
    if (depth > maxDepth) return;
    var indent = new string(' ', depth * 2);

    // Only print certain node types
    if (node is P || node is Target || node is Error || node is Warning)
    {
        string label = node switch
        {
            P p => $"[Project] {p.Name}",
            Target t => $"[Target] {t.Name}",
            Error e => $"[ERROR] {e.Code}: {e.Text}",
            Warning w => $"[WARN] {w.Code}: {w.Text}",
            _ => node.ToString() ?? ""
        };
        Console.WriteLine($"{indent}{label}");
    }

    if (node.HasChildren)
    {
        foreach (var child in node.Children.OfType<BaseNode>())
        {
            PrintTree(child, depth + (node is P || node is Target || node is Error ? 1 : 0), maxDepth);
        }
    }
}
